const data = $input.first().json;

const webhookMap = {
  MEDICAL: 'YOUR_SLACK_WEBHOOK_MEDICAL',
  ORDER: 'YOUR_SLACK_WEBHOOK_ORDER',
  BUSINESS: 'YOUR_SLACK_WEBHOOK_BUSINESS',
  FAQ: 'YOUR_SLACK_WEBHOOK_FAQ'
};

const priorityEmoji = { P1: '🚨', P2: '⚠️', P3: 'ℹ️' };

const webhookUrl = webhookMap[data.category] || webhookMap['FAQ'];
const emoji = priorityEmoji[data.priority] || 'ℹ️';
const urgentPrefix = data.priority === 'P1' ? '🚨 *HITNO / URGENT* 🚨\n' : '';

const message = `${urgentPrefix}${emoji} *Nova poruka — ${data.category}* (${data.priority})\n` +
  `*Od:* ${data.sender}\n` +
  `*Predmet:* ${data.subject}\n` +
  `*Sažetak:* ${data.summary}\n` +
  `*Akcija:* ${data.suggested_action}\n` +
  `*Auto-odgovor:* ${data.requires_human ? 'Ne — čeka odgovor' : 'Da'}`;

return [{ json: { webhookUrl, message, isP1: data.priority === 'P1', ...data } }];

